import React from 'react'
import { Link } from 'react-router-dom'
import '../styles/Burger.scss'

const Burger = ({ burger, items, isActive, setIsActive, lang, page="designer" }) => {
    return (
        <>
            <div className={`burger ${burger}`} onClick={() => setIsActive(true)}>
                <span />
                <span />
                <span />
            </div>

            <div className={isActive ? "burger-menu burger-menu_active" : "burger-menu"}>
                <div className="burger-menu__menu">
                    <Link className="burger-menu__lang" to={lang.toLowerCase() === 'en' ? `/${page}-ru` : `/${page}-en`}>{lang.toUpperCase()}</Link>
                    <div className="burger-menu__cross" onClick={() => setIsActive(false)} />
                </div>
                <div className="burger-menu__content">
                    {items.map(item => item.type === 'link' ? <Link key={item.text} className={"burger-menu__item"} to={item.path}>{item.text}</Link> : <a key={item.text} className={"burger-menu__item"} href={item.path}>{item.text}</a>)}
                </div>
            </div>
        </>
    )
}

export default Burger