import React from 'react'
import FrontenderPage from './pages/Frontender'
import FrontenderRuPage from './pages/FrontenderRu'
import DesignerPage from './pages/Designer'
import DesignerRuPage from './pages/DesignerRu'
import { ParallaxProvider } from 'react-scroll-parallax'
import { HashRouter, Route, Routes, Navigate } from 'react-router-dom'

const App = () => {
  	return <ParallaxProvider><HashRouter>
		<Routes>
			<Route path="/designer-ru" element={<DesignerRuPage />} />
			<Route path="/designer-en" element={<DesignerPage />} />
			<Route path="/designer" element={<DesignerRuPage />} />
			<Route path="/frontender" element={<FrontenderRuPage />} />
			<Route path="/frontender-ru" element={<FrontenderRuPage />} />
			<Route path="/frontender-en" element={<FrontenderPage />} />
			<Route path="*" element={<Navigate to="/designer-ru" />} />
		</Routes>
  	</HashRouter></ParallaxProvider>
}

export default App
