import React from 'react'
import '../styles/Loader.scss'

const Loader = ({ type='designer' }) => {
    if (type === 'frontender') return (
        <img className="loader" src="/static/frontend/loader.svg" alt="Идёт загрузка..." />
    ) 

    return (
        <img className="loader" src="/static/design/loader.svg" alt="Идёт загрузка..." />
    )
}

export default Loader